import datetime
import sys

def log(msg, level='INFO'):
    t = datetime.datetime.now()
    print('[' + str(t) + '] ' + level + ': ' + msg, file = sys.stderr)

def log_error(msg):
    log(msg, level = 'ERROR')

def log_warn(msg):
    log(msg,'WARN')

class userSession:
    def __init__(self,userid,token,expiry):
        self.userid=userid
        self.Token=token
        self.Expiry=expiry
    def is_valid(self):
        import datetime
        return datetime.datetime.now() < self.Expiry
